 1	import React, { Dispatch, FC, MouseEvent, SetStateAction, useMemo } from 'react';
 2	
 3	import FormGroupHelperText from '@kubevirt-utils/components/FormGroupHelperText/FormGroupHelperText';
 4	import FormPFSelect from '@kubevirt-utils/components/FormPFSelect/FormPFSelect';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { interfacesTypes } from '@kubevirt-utils/resources/vm/utils/network/constants';
 7	import { FormGroup, SelectOption } from '@patternfly/react-core';
 8	
 9	import { networkNameStartWithPod } from '../utils/helpers';
10	
11	type NetworkInterfaceTypeSelectProps = {
12	  interfaceType: string;
13	  networkName: string | undefined;
14	  setInterfaceType: Dispatch<SetStateAction<string>>;
15	  showTypeHelperText?: boolean;
16	};
17	
18	const NetworkInterfaceTypeSelect: FC<NetworkInterfaceTypeSelectProps> = ({
19	  interfaceType,
20	  networkName,
21	  setInterfaceType,
22	  showTypeHelperText,
23	}) => {
24	  const { t } = useKubevirtTranslation();
25	  const isPodNetworkName = useMemo(() => networkNameStartWithPod(networkName), [networkName]);
26	
27	  const interfaceTypeOptions = {
28	    bridge: {
29	      // in case of NAD network, networkName should be a string - enabled if nad type is bridge or undefined or no nad
30	      allowOption:
31	        !isPodNetworkName &&
32	        (interfaceType === interfacesTypes.bridge || !interfaceType || !networkName),
33	      description: t(
34	        'The VirtualMachine will be bridged to the selected network, ideal for L2 devices',
35	      ),
36	      id: interfacesTypes.bridge,
37	      name: t('Bridge'),
38	    },
39	    masquerade: {
40	      // in case of pod network, networkName is undefined
41	      allowOption: isPodNetworkName,
42	      description: t(
43	        'Put the VirtualMachine behind a NAT Proxy for high compatibility with different network providers. The VirtualMachines IP will differ from the IP seen on the pod network',
44	      ),
45	      id: interfacesTypes.masquerade,
46	      name: t('Masquerade'),
47	    },
48	    sriov: {
49	      // in case of NAD network, networkName should be a string - enabled if nad type is sriov or undefined or no nad
50	      allowOption:
51	        !isPodNetworkName &&
52	        (interfaceType === interfacesTypes.sriov || !interfaceType || !networkName),
53	      description: t(
54	        'Attach a virtual function network device to the VirtualMachine for high performance',
55	      ),
56	      id: interfacesTypes.sriov,
57	      name: t('SR-IOV'),
58	    },
59	  };
60	
61	  const handleChange = (event: MouseEvent<HTMLSelectElement>, value: string) => {
62	    event.preventDefault();
63	    setInterfaceType(value);
64	  };
65	
66	  return (
67	    <FormGroup fieldId="type" label={t('Type')}>
68	      <div data-test-id="network-interface-type-select">
69	        <FormPFSelect
70	          onSelect={handleChange}
71	          selected={interfaceType}
72	          toggleProps={{ isFullWidth: true }}
73	        >
74	          {Object.values(interfaceTypeOptions)
75	            ?.filter(({ allowOption }) => allowOption)
76	            ?.map(({ description, id, name }) => (
77	              <SelectOption
78	                data-test-id={`network-interface-type-select-${id}`}
79	                description={description}
80	                key={id}
81	                value={id}
82	              >
83	                {name}
84	              </SelectOption>
85	            ))}
86	        </FormPFSelect>
87	        <FormGroupHelperText>
88	          {showTypeHelperText && t('Hot plug is enabled only for "Bridge" and "SR-IOV" types')}
89	        </FormGroupHelperText>
90	      </div>
91	    </FormGroup>
92	  );
93	};
94	
95	export default NetworkInterfaceTypeSelect;

